            onClick={() => {
              onClose();
              setOpen(false);
            }}
            size="small"
          >
            Cancel
          </Button>
          <Button
            as="button"
            disabled={confirmDisabled}
            onClick={(e) => {
              onConfirm(e);
              setOpen(false);
            }}
            size="small"
            variant="primary"
          >
            {confirmText}
          </Button>
        </ButtonWrapper>
      </ContentWrapper>
    </Tooltip>
